beginning.embedded_functions:
// Function to check if packet rate exceeds a defined threshold
// Parameters:
//   - packet_count: The number of packets within the time window
//   - rate_threshold: The rate threshold to exceed (packets per second)
//   - time_window_seconds: The time window to consider (seconds)
// Returns:
//   - 1 if the rate exceeds the threshold
//   - 0 otherwise
static inline int packet_rate_exceeds_threshold(int packet_count, int rate_threshold, int time_window_seconds) {
  if (packet_count > rate_threshold * time_window_seconds) {
    return 1;
  } else {
    return 0;
  }
}
